previewCss:
.darma-loader-darma-custom-390 {color: var(--loader-color, #9333ea);
  --loader-secondary-color: #f0abfc;
  --loader-bg: #ffffff;
  width: 120px;
  height: 20px;
  background:radial-gradient(circle closest-side,var(--loader-color, #9333ea) 94%,#0000) 50% 50%/calc(50% + 10px) 70% repeat-x var(--loader-secondary-color, #f0abfc);
  animation: darma-loader-darma-custom-390-l9 1s infinite cubic-bezier(0.3,1,0,1);
}@keyframes darma-loader-darma-custom-390-l9 {100% {background-position: calc(200% - 5px)}}

